// animationNumbers replicates mudclient.loadEntitiesAuthentic's sprite-block base
// assignment: walk the defs, dedup by NAME (a repeated name shares the earlier
// base), assigning +27 per unique name with the 1998->3300 jump. The frame sprite
// id in Authentic_Sprites.orsc is animationNumbers()[animID] + frame.
func animationNumbers() []int {
	nums := make([]int, len(authenticAnimDefs))
	seen := map[string]int{}
	n := 0
	for i, d := range authenticAnimDefs {
		if prev, ok := seen[d.name]; ok {
			nums[i] = prev
			continue
		}
		nums[i] = n
		seen[d.name] = n
		n += 27
		if n == 1998 {
			n = 3300
		}
	}
	return nums
}
